import classes from './ServerSidebar.module.css'

const ServerSidebar = () => {
  return (
    <nav>
      <div className={classes['server-list']}>
        <ServerIcon></ServerIcon>
        <ServerIcon></ServerIcon>
        <ServerIcon></ServerIcon>
        <ServerIcon></ServerIcon>
        <ServerIcon></ServerIcon>
      </div>
    </nav>
  );
};


export default ServerSidebar
